const s="./api",i={async getConnectors(){const n=await fetch(`${s}/connectors`);if(!n.ok)throw new Error("Fehler beim Laden der Connectoren");return n.json()},async testConnection(n,e,t,o){const r=await fetch(`${s}/connectors/test`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({connector_id:n,host:e,username:t,password:o})});if(!r.ok){const c=await r.json();throw new Error(c.detail||"Verbindungstest fehlgeschlagen")}return r.json()},async setup(n,e,t,o,r){const c=await fetch(`${s}/connectors/setup/${n}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({connector_id:e,host:t,username:o,password:r})});if(!c.ok){const a=await c.json();throw new Error(a.detail||"Einrichtung fehlgeschlagen")}return c.json()},async getStatus(n){const e=await fetch(`${s}/connectors/status/${n}`);if(!e.ok)throw new Error("Fehler beim Laden des Connector-Status");return e.json()},async fetch(n){const e=await fetch(`${s}/connectors/fetch/${n}`,{method:"POST"});if(!e.ok){const t=await e.json();throw new Error(t.detail||"Ablesung fehlgeschlagen")}return e.json()},async remove(n){const e=await fetch(`${s}/connectors/${n}`,{method:"DELETE"});if(!e.ok){const t=await e.json();throw new Error(t.detail||"Entfernen fehlgeschlagen")}},async getMonatswerte(n,e,t){const o=await fetch(`${s}/connectors/monatswerte/${n}/${e}/${t}`);if(!o.ok){const r=await o.json();throw new Error(r.detail||"Keine Connector-Daten für diesen Monat")}return o.json()}};export{i as c};
